requestEjs.python:
from openai import OpenAI

client = OpenAI(
  base_url = "https://integrate.api.nvidia.com/v1",
  api_key = "$NVIDIA_API_KEY"
)
<%
const extra_body = {};
const reasoning_effort = request.reasoning_effort || "high";
if (request.chat_template_kwargs) {
  extra_body["chat_template_kwargs"] = request.chat_template_kwargs;
} else if (reasoning_effort === "none") {
  extra_body["chat_template_kwargs"] = {"enable_thinking": false};
} else if (reasoning_effort === "low") {
  extra_body["chat_template_kwargs"] = {"enable_thinking": true, "low_effort": true};
} else {
  extra_body["chat_template_kwargs"] = {"enable_thinking": true};
}
if (request.reasoning_budget !== undefined && request.reasoning_budget !== null
    && reasoning_effort !== "none") {
  extra_body["reasoning_budget"] = request.reasoning_budget;
}
const reasoning_enabled = !!(extra_body["chat_template_kwargs"] &&
  extra_body["chat_template_kwargs"]["enable_thinking"]);
const extra_body_py = Object.keys(extra_body).length
  ? JSON.stringify(extra_body)
      .replaceAll("true", "True")
      .replaceAll("false", "False")
      .replaceAll("null", "None")
  : null;
%>
<% if (request.tools) { %>
completion = client.chat.completions.create(
  model="<%- request.model %>",
  messages=<%- JSON.stringify(request.messages) %>,
  temperature=<%- request.temperature %>,
  top_p=<%- request.top_p %>,
  max_tokens=<%- request.max_tokens %>,
  <%- extra_body_py ? 'extra_body=' + extra_body_py + ',' : '' %>
  stream=<%- request.stream?.toString()[0].toUpperCase() + request.stream?.toString().slice(1) %>,
  tools=<%- JSON.stringify(request.tools) %>,
  <% if (request.tool_choice) { %>tool_choice=<%- JSON.stringify(request.tool_choice) %><% } %>
)<% } else { %>
completion = client.chat.completions.create(
  model="<%- request.model %>",
  messages=<%- JSON.stringify(request.messages) %>,
  temperature=<%- request.temperature %>,
  top_p=<%- request.top_p %>,
  max_tokens=<%- request.max_tokens %>,
  <%- extra_body_py ? 'extra_body=' + extra_body_py + ',' : '' %>
  stream=<%- request.stream?.toString()[0].toUpperCase() + request.stream?.toString().slice(1) %>
)<% } %>
<% if (request.stream) { %>
for chunk in completion:
  if not chunk.choices:
    continue
<% if (reasoning_enabled) { -%>
  reasoning = getattr(chunk.choices[0].delta, "reasoning_content", None)
  if reasoning:
    print(reasoning, end="")
<% } -%>
  if chunk.choices[0].delta.content is not None:
    print(chunk.choices[0].delta.content, end="")
  <% if (request.tools) { %>if chunk.choices[0].delta.tool_calls:
    print(chunk.choices[0].delta.tool_calls)<% } %>
<% } else { %>
<% if (reasoning_enabled) { -%>
reasoning = getattr(completion.choices[0].message, "reasoning_content", None)
if reasoning:
  print(reasoning)
<% } -%>
print(completion.choices[0].message.content)
<% if (request.tools) { %>if completion.choices[0].message.tool_calls:
  print(completion.choices[0].message.tool_calls)<% } %>
<% } %>

requestEjs.node.js:
import OpenAI from 'openai';

const openai = new OpenAI({
  apiKey: '$NVIDIA_API_KEY',
  baseURL: 'https://integrate.api.nvidia.com/v1',
})
<%
const node_reasoning_effort = request.reasoning_effort || "high";
const node_chat_template_kwargs = request.chat_template_kwargs
  ? request.chat_template_kwargs
  : (node_reasoning_effort === "none"
      ? {"enable_thinking": false}
      : (node_reasoning_effort === "low"
          ? {"enable_thinking": true, "low_effort": true}
          : {"enable_thinking": true}));
const node_reasoning_enabled = !!(node_chat_template_kwargs && node_chat_template_kwargs.enable_thinking);
%>
 <% if (request.tools) { %>
async function main() {
  const completion = await openai.chat.completions.create({
    model: "<%- request.model %>",
    messages: <%- JSON.stringify(request.messages) %>,
    temperature: <%- request.temperature %>,
    top_p: <%- request.top_p %>,
    max_tokens: <%- request.max_tokens %>,
    <%- (request.reasoning_budget !== undefined && request.reasoning_budget !== null && node_reasoning_effort !== "none") ? 'reasoning_budget: ' + request.reasoning_budget + ',' : '' %>
    <%- node_chat_template_kwargs ? 'chat_template_kwargs: ' + JSON.stringify(node_chat_template_kwargs) + ',' : '' %>
    stream: <%- request.stream %>,
    <% if (request.tools) { %>tools: <%- JSON.stringify(request.tools) %>,<% } %>
    <% if (request.tool_choice) { %>tool_choice: <%- JSON.stringify(request.tool_choice) %>,<% } %>
  })<% } else { %>
async function main() {
  const completion = await openai.chat.completions.create({
    model: "<%- request.model %>",
    messages: <%- JSON.stringify(request.messages) %>,
    temperature: <%- request.temperature %>,
    top_p: <%- request.top_p %>,
    max_tokens: <%- request.max_tokens %>,
    <%- (request.reasoning_budget !== undefined && request.reasoning_budget !== null && node_reasoning_effort !== "none") ? 'reasoning_budget: ' + request.reasoning_budget + ',' : '' %>
    <%- node_chat_template_kwargs ? 'chat_template_kwargs: ' + JSON.stringify(node_chat_template_kwargs) + ',' : '' %>
    stream: <%- request.stream %>
  })<% } %>
   <% if (request.stream) { %>
  for await (const chunk of completion) {
    <% if (node_reasoning_enabled) { -%>
    const reasoning = chunk.choices[0]?.delta?.reasoning_content;
    if (reasoning) process.stdout.write(reasoning);
    <% } -%>
    process.stdout.write(chunk.choices[0]?.delta?.content || '')
    <% if (request.tools) { %>if (chunk.choices[0]?.delta?.tool_calls) console.log(chunk.choices[0]?.delta?.tool_calls)<% } %>
  }
  <% } else { %>
  <% if (node_reasoning_enabled) { -%>
  const reasoning = completion.choices[0]?.message?.reasoning_content;
  if (reasoning) process.stdout.write(reasoning + "\n");
  <% } -%>
  process.stdout.write(completion.choices[0]?.message?.content || '');
  <% if (request.tools) { %>if (completion.choices[0]?.message?.tool_calls) console.log(completion.choices[0]?.message?.tool_calls);<% } %>
  <% } %>
}

main();

